import { useState, useRef, useEffect } from "react";
import { NavLink, useNavigate } from "react-router-dom";
import { useCart } from "../context/CartContext";
import { useAuth } from "../context/AuthContext";
import { useNotification } from "../context/NotificationContext"; // Kéo context thông báo vào

function Menu() {
  const { cartCount } = useCart();
  const { user, logout } = useAuth();
  const { notifications, unreadCount, markAllAsRead } = useNotification();
  const navigate = useNavigate();
  
  const [searchText, setSearchText] = useState("");
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const [notifOpen, setNotifOpen] = useState(false);
  
  const dropdownRef = useRef(null);
  const notifRef = useRef(null);

  // Xử lý click ra ngoài để đóng các dropdown
  useEffect(() => {
    const handleClickOutside = (e) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) setDropdownOpen(false);
      if (notifRef.current && !notifRef.current.contains(e.target)) setNotifOpen(false);
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const handleSearch = () => {
    if (searchText.trim()) {
      navigate(`/products?search=${encodeURIComponent(searchText.trim())}`);
      setSearchText("");
    }
  };

  const handleLogout = () => {
    logout();
    navigate("/");
  };

  const isAdmin = user?.role === "admin";

  return (
    <header style={styles.header}>
      <div style={styles.topBar}>
        {/* Logo */}
        <div style={styles.logo} onClick={() => navigate("/")}>
          <span style={styles.logoIcon}>🌿</span>
          <div>
            <span style={styles.logoText}>FreshMart</span>
            <span style={styles.logoSub}>Siêu Thị Thực Phẩm Sạch</span>
          </div>
        </div>

        {/* Search */}
        <div style={styles.searchBar}>
          <span style={styles.searchIconLeft}>🔍</span>
          <input
            type="text"
            placeholder="Tìm kiếm sản phẩm tươi sạch..."
            value={searchText}
            onChange={(e) => setSearchText(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && handleSearch()}
            style={styles.searchInput}
          />
          <button style={styles.searchBtn} onClick={handleSearch}>Tìm kiếm</button>
        </div>

        {/* Top Right */}
        <div style={styles.topRight}>
          
          {/* Thông báo (MỚI) */}
          {user && (
            <div style={styles.notifWrapper} ref={notifRef}>
              <div 
                style={styles.iconBtn} 
                onClick={() => {
                  setNotifOpen(!notifOpen);
                  if (!notifOpen && unreadCount > 0) markAllAsRead();
                }}
              >
                <span style={{ fontSize: "20px" }}>🔔</span>
                {unreadCount > 0 && <span style={styles.badge}>{unreadCount}</span>}
              </div>

              {notifOpen && (
                <div style={styles.notifDropdown}>
                  <h4 style={styles.notifTitle}>Thông báo mới</h4>
                  <div style={styles.notifList}>
                    {notifications.length === 0 ? (
                      <p style={styles.notifEmpty}>Chưa có thông báo nào</p>
                    ) : (
                      notifications.map(n => (
                        <div key={n.id} style={{...styles.notifItem, backgroundColor: n.read ? "white" : "#f0fdf4"}}>
                          <p style={styles.notifText}>{n.text}</p>
                          <p style={styles.notifDate}>{new Date(n.date).toLocaleString("vi-VN")}</p>
                        </div>
                      ))
                    )}
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Cart */}
          <div style={styles.iconBtn} onClick={() => navigate("/cart")}>
            <span style={{ fontSize: "20px" }}>🛒</span>
            {cartCount > 0 && <span style={styles.badge}>{cartCount}</span>}
          </div>

          {/* User */}
          {user ? (
            <div style={styles.userBox} ref={dropdownRef}>
              <div style={styles.userTrigger} onClick={() => setDropdownOpen(!dropdownOpen)}>
                <div style={{ ...styles.avatar, backgroundColor: isAdmin ? "#ef4444" : "#22c55e" }}>
                  {user.name.charAt(0).toUpperCase()}
                </div>
                <div style={styles.userInfo}>
                  <span style={styles.userName}>Xin chào, {user.name.split(" ").pop()}</span>
                </div>
              </div>

              {dropdownOpen && (
                <div style={styles.dropdownMenu}>
                  {isAdmin ? (
                    <button style={styles.dropdownItem} onClick={() => { navigate("/admin"); setDropdownOpen(false); }}>⚙️ Quản trị</button>
                  ) : (
                    <>
                      <button style={styles.dropdownItem} onClick={() => { navigate("/order"); setDropdownOpen(false); }}>📦 Đơn hàng</button>
                      <button style={styles.dropdownItem} onClick={() => { navigate("/lucky-wheel"); setDropdownOpen(false); }}>🎡 Vòng quay</button>
                    </>
                  )}
                  <div style={styles.dropdownDivider} />
                  <button style={styles.dropdownItemLogout} onClick={() => { handleLogout(); setDropdownOpen(false); }}>🚪 Đăng xuất</button>
                </div>
              )}
            </div>
          ) : (
            <button style={styles.loginBtn} onClick={() => navigate("/login")}>👤 Đăng nhập</button>
          )}
        </div>
      </div>
    </header>
  );
}

const styles = {
